import { CommandHandler, type ICommandHandler } from "@nestjs/cqrs";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";
import { Transactional } from "typeorm-transactional";

import { PaymentEntity } from "../../payment.entity.ts";
import { PaymentNotFoundException } from "../../exceptions/payment-not-found.exception.ts";
import { UpdatePaymentCommand } from "./update-payment.command.ts";

@CommandHandler(UpdatePaymentCommand)
export class UpdatePaymentHandler
  implements ICommandHandler<UpdatePaymentCommand, PaymentEntity>
{
  constructor(
    @InjectRepository(PaymentEntity)
    private readonly paymentRepository: Repository<PaymentEntity>,
  ) {}

  @Transactional()
  async execute(command: UpdatePaymentCommand): Promise<PaymentEntity> {
    const { paymentId, updatePaymentDto } = command;

    const payment = await this.paymentRepository.findOne({
      where: { id: paymentId },
    });

    if (!payment) {
      throw new PaymentNotFoundException(paymentId);
    }

    Object.assign(payment, updatePaymentDto);

    return this.paymentRepository.save(payment);
  }
}
